import { useState, useEffect } from "react";
import { useLocation } from "react-router-dom";
import NavbarGestionSalas from "../components/NavbarGestionSalas";
import FooterRojo from "../components/FooterRojo";
import "../styles/EditarSalaCompleto.css";

function EditarSala() {
  const location = useLocation();
  const salaInicial = location.state?.sala;

  const [tab, setTab] = useState("info");
  const [salaSeleccionada, setSalaSeleccionada] = useState(salaInicial);

  const [form, setForm] = useState({
    nombre: "",
    ubicacion: "",
    capacidad: ""
  });

  const [estado, setEstado] = useState("");

  // 🔥 CARGAR DATOS AL ENTRAR
  useEffect(() => {
    if (salaInicial) {
      setForm({
        nombre: salaInicial.nombre,
        ubicacion: salaInicial.ubicacion,
        capacidad: salaInicial.capacidad
      });

      setEstado(salaInicial.estado);
    }
  }, [salaInicial]);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  // 🔹 EDITAR INFO
  const editarInfo = async () => {
    if (!salaSeleccionada) return;

    await fetch(
      `http://localhost:3001/api/salas/${salaSeleccionada.id}/datos`,
      {
        method: "PUT",
        credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          nombre: form.nombre,
          ubicacion: form.ubicacion,
          capacidad: Number(form.capacidad)
        })
      }
    );

    alert("Información actualizada ✅");
  };

  // 🔹 EDITAR ESTADO
  const editarEstado = async () => {
    if (!salaSeleccionada) return;

    await fetch(
      `http://localhost:3001/api/salas/${salaSeleccionada.id}`,
      {
        method: "PUT",
        credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          estado: estado.toLowerCase()
        })
      }
    );

    alert("Estado actualizado ✅");
  };

  return (
    <div className="container">
      <NavbarGestionSalas />

      <div className="content">

        <div className="formSection">

          <h2>
            {salaSeleccionada
              ? `Editando: ${salaSeleccionada.nombre}`
              : "No hay sala seleccionada"}
          </h2>

          {/* 🔥 TABS */}
          <div className="tabs">
            <button
              className={tab === "info" ? "active" : ""}
              onClick={() => setTab("info")}
            >
              Información
            </button>

            <button
              className={tab === "estado" ? "active" : ""}
              onClick={() => setTab("estado")}
            >
              Estado
            </button>
          </div>

          {/* 🔹 INFO */}
          {tab === "info" && (
            <>
              <div className="formGroup">
                <label>Nombre</label>
                <input
                  name="nombre"
                  value={form.nombre}
                  onChange={handleChange}
                />
              </div>

              <div className="formGroup">
                <label>Ubicación</label>
                <input
                  name="ubicacion"
                  value={form.ubicacion}
                  onChange={handleChange}
                />
              </div>

              <div className="formGroup">
                <label>Capacidad</label>
                <input
                  type="number"
                  name="capacidad"
                  value={form.capacidad}
                  onChange={handleChange}
                />
              </div>

              <button className="btn azul" onClick={editarInfo}>
                Guardar Cambios
              </button>
            </>
          )}

          {/* 🔹 ESTADO */}
          {tab === "estado" && (
            <>
              <div className="formGroup">
                <label>Estado</label>
                <select
                  value={estado}
                  onChange={(e) => setEstado(e.target.value)}
                >
                  <option value="">Seleccione</option>
                  <option value="disponible">Disponible</option>
                  <option value="ocupado">Ocupado</option>
                  <option value="mantenimiento">Mantenimiento</option>
                </select>
              </div>

              <button className="btn rojo" onClick={editarEstado}>
                Actualizar Estado
              </button>
            </>
          )}

        </div>

      </div>

      <FooterRojo />
    </div>
  );
}

export default EditarSala;
